class Solution:
    def countOfAtoms(self, formula: str) -> str:
        i, n, stack = 0, len(formula), [{}]
        while i < n:
            if formula[i] == '(':
                stack.append({})
                i += 1
            elif formula[i] == ')':
                top = stack.pop()
                i += 1
                i_start = i
                while i < n and formula[i].isdigit():
                    i += 1
                multiplicity = int(formula[i_start:i] or 1)
                for name, v in top.items():
                    stack[-1][name] = stack[-1].get(name, 0) + v * multiplicity
            else:
                i_start = i
                i += 1
                while i < n and formula[i].islower():
                    i += 1
                name = formula[i_start:i]
                i_start = i
                while i < n and formula[i].isdigit():
                    i += 1
                multiplicity = int(formula[i_start:i] or 1)
                stack[-1][name] = stack[-1].get(name, 0) + multiplicity
        ans = []
        for name, v in sorted(stack[-1].items()):
            ans.append(name)
            if v > 1:
                ans.append(str(v))
        return ''.join(ans)
